const today = $now.toFormat('yyyy-MM-dd');
const staticData = $getWorkflowStaticData('global');
if (staticData.countDate !== today) {
  staticData.countDate = today;
  staticData.dailyCount = 0;
}
const item = $input.first().json;
return [{ json: { ...item, dailyTicketCount: staticData.dailyCount, todayDate: today } }];

