// output[0] = Erfolg  |  output[1] = Fehler
try {
  const aiResponse = items[0].json.choices[0].message.content;
  let parsed;
  try { parsed = JSON.parse(aiResponse); }
  catch (e) { parsed = { title: 'Neues Ticket', category: 'technical', priority: 'medium', deadline: null, description: '', subtasks: [] }; }

  const emailData = $items('🔧 Mail normalisieren')[0].json;
  const bodyText = emailData.text || emailData.html || '';
  const senderMatch = bodyText.match(/REPLY_TO_EMAIL:\s*([^\n\r<]+)/i);
  const emailRegex = /[\w.+\-]+@[\w\-]+\.[\w.]+/;
  const fromRaw = emailData.replyTo || emailData.from || '';
  const fromMatch = fromRaw.match(emailRegex);
  const senderEmail = (senderMatch && senderMatch[1].trim())
    || (fromMatch && fromMatch[0])
    || fromRaw.replace(/^["'\s<>]+|["'\s<>]+$/g, '').trim();

  const kiHinweis = '\n\n---\n⚠️ KI-generiert aus E-Mail von: ' + senderEmail;

  const rawSubtasks = Array.isArray(parsed.subtasks) ? parsed.subtasks : [];
  const subtasks = rawSubtasks
    .filter(function(t) { return typeof t === 'string' && t.trim().length > 0; })
    .slice(0, 4)
    .map(function(t, i) { return { id: Date.now() + i, text: t.trim(), completed: false }; });

  return [[{ json: {
    title: parsed.title,
    category: parsed.category || 'technical',
    priority: parsed.priority || 'medium',
    deadline: parsed.deadline,
    description: (parsed.description || '') + kiHinweis,
    subtasks: subtasks,
    senderEmail: senderEmail,
    originalSubject: emailData.subject
  }}], []];
} catch (e) {
  const emailData = items[0].json;
  const fromRaw = emailData.replyTo || emailData.from || '';
  const fromMatch = fromRaw.match(/[\w.+\-]+@[\w\-]+\.[\w.]+/);
  return [[], [{ json: { error: e.message, senderEmail: (fromMatch && fromMatch[0]) || 'unknown' } }]];
}

// Wandelt die verschachtelte Gmail-Struktur in flache Felder um,
// die alle nachfolgenden Nodes erwarten (from, subject, text ...).
const msg = items[0].json;

function findHeader(name) {
  const headers = (msg.payload && msg.payload.headers) || [];
  const hit = headers.find(function (h) {
    return h.name && h.name.toLowerCase() === name.toLowerCase();
  });
  return hit ? hit.value : '';
}

function decodeBase64Url(data) {
  if (!data) return '';
  return Buffer.from(data.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8');
}

function extractBody() {
  const payload = msg.payload || {};
  if (payload.body && payload.body.data) return decodeBase64Url(payload.body.data);
  const parts = payload.parts || [];
  const plain = parts.find(function (p) { return p.mimeType === 'text/plain'; });
  if (plain && plain.body && plain.body.data) return decodeBase64Url(plain.body.data);
  const html = parts.find(function (p) { return p.mimeType === 'text/html'; });
  if (html && html.body && html.body.data) return decodeBase64Url(html.body.data);
  return msg.snippet || '';
}

const flat = {
  from: msg.from || findHeader('From'),
  replyTo: msg.replyTo || findHeader('Reply-To'),
  subject: msg.subject || findHeader('Subject'),
  text: msg.text || extractBody(),
  messageId: msg.id || '',
  threadId: msg.threadId || ''
};

return [{ json: Object.assign({}, msg, flat) }];
